export const NEGATIVE_PROMPT =
  "Не изменяй остальную часть изображения, не меняй людей, мебель, архитектуру, ракурс и композицию вне указанной области, избегай лишних объектов, дешёвого вида, визуального шума, деформаций, неестественной флористики, неправильной перспективы, несоответствия света и теней, перенасыщенности и хаотичного декора.";

/**
 * Try to detect "preset N" in user message and optional area override.
 * Examples: "150", "пресет 150", "150 во входной зоне", "сделай 27 на потолке"
 */
export function tryMatchPreset(userMessage: string): { preset: Preset; area: string | null } | null {
  const text = userMessage.trim();
  if (!text) return null;

  // Find a standalone number 1..196
  const match = text.match(/(?:^|[^\d])(\d{1,3})(?!\d)/);
  if (!match) return null;
  const n = parseInt(match[1], 10);
  if (!Number.isFinite(n) || n < 1 || n > PRESETS.length) return null;

  const preset = PRESETS[n - 1];
  // Try extract area: anything after the number
  const afterNumber = text.slice(text.indexOf(match[1]) + match[1].length).trim();
  // Strip leading punctuation/words like "в", "во", ":", "—"
  const areaMatch = afterNumber.replace(/^[\s,—:.\-]+/u, "").replace(/^(в|во|на|для)\s+/iu, "").trim();
  const area = areaMatch.length >= 3 ? areaMatch : null;

  return { preset, area };
}

export function buildPresetResponse(preset: Preset, area: string | null) {
  const finalPrompt = area
    ? preset.prompt.replace(/\[ОБЛАСТЬ\]/g, area)
    : preset.prompt;

  const content =
    `${finalPrompt}\n\n` +
    `Использованный пресет: ${preset.id}. ${preset.name}\n` +
    `Область: ${area ?? "[ОБЛАСТЬ]"}\n` +
    `Negative prompt: ${NEGATIVE_PROMPT}`;

  return {
    content,
    finalPrompt,
    preset: `${preset.id}. ${preset.name}`,
    area: area ?? "[ОБЛАСТЬ]",
    negative: NEGATIVE_PROMPT,
  };
}